namespace sv_eff8274fd0c04794ad69865263f57081.Models;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class Notification
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

using sv_eff8274fd0c04794ad69865263f57081.Models;

namespace sv_eff8274fd0c04794ad69865263f57081.Services;

/// <summary>
/// Scoped per-circuit service that holds notification state and raises
/// <see cref="OnChange"/> so every subscribed component can re-render
/// when any mutation occurs — even if a different component triggered it.
/// </summary>
public sealed class NotificationHub
{
    private readonly List<Notification> _notifications = [];
    private readonly object _lock = new();

    /// <summary>
    /// Subscribers add async callbacks here. Each component registers one
    /// delegate and removes it on dispose. The hub invokes every delegate
    /// after each mutation so all components stay in sync.
    /// </summary>
    public event Func<Task>? OnChange;

    public IReadOnlyList<Notification> Notifications
    {
        get
        {
            lock (_lock)
            {
                return _notifications.OrderByDescending(n => n.Severity)
                                     .ThenByDescending(n => n.Timestamp)
                                     .ToList();
            }
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock)
        {
            return _notifications.Count(n => !n.IsRead);
        }
    }

    public async Task AddNotificationAsync(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Add(new Notification
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        await NotifyAsync();
    }

    public async Task MarkAsReadAsync(Guid id)
    {
        lock (_lock)
        {
            var item = _notifications.FirstOrDefault(n => n.Id == id);
            if (item is not null)
                item.IsRead = true;
        }
        await NotifyAsync();
    }

    public async Task MarkAllReadAsync()
    {
        lock (_lock)
        {
            foreach (var n in _notifications)
                n.IsRead = true;
        }
        await NotifyAsync();
    }

    public async Task DismissNotificationAsync(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        if (OnChange is not null)
        {
            // Invoke every subscriber. Each delegate is expected to call
            // InvokeAsync(StateHasChanged) so the right sync-context is used.
            foreach (var handler in OnChange.GetInvocationList().Cast<Func<Task>>())
            {
                await handler();
            }
        }
    }
}

using sv_eff8274fd0c04794ad69865263f57081.Models;

namespace sv_eff8274fd0c04794ad69865263f57081.Services;

/// <summary>
/// Adds a random notification every 15 seconds. Started/stopped by the
/// Dashboard page so it only runs while that page is active.
/// Timer fires on a thread-pool thread — all UI updates are marshalled
/// through <see cref="NotificationHub.OnChange"/> → component InvokeAsync.
/// </summary>
public sealed class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    private static readonly string[] Titles =
    [
        "Deployment complete", "CPU spike detected", "Disk space low",
        "New user signup", "Payment processed", "SSL cert expiring",
        "Build failed", "Service restarted", "Memory threshold exceeded",
        "Backup finished"
    ];

    private static readonly string[] Messages =
    [
        "Check the operations dashboard for details.",
        "Automated monitoring flagged this event.",
        "Review recommended within 24 hours.",
        "No immediate action required.",
        "Escalation policy may apply."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_cts is not null) return; // already running

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        _ = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
        _cts = null;
        _timer = null;
    }

    private async Task RunAsync(CancellationToken ct)
    {
        var rng = Random.Shared;
        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            var severity = (Severity)rng.Next(0, 3);
            var title = Titles[rng.Next(Titles.Length)];
            var message = Messages[rng.Next(Messages.Length)];

            // This runs on a thread-pool thread. AddNotificationAsync raises
            // OnChange, whose subscribers call InvokeAsync(StateHasChanged)
            // to marshal back to the render sync-context.
            await _hub.AddNotificationAsync(title, message, severity);
        }
    }

    public void Dispose() => Stop();
}

