@* Interactive island embedded in the static NavMenu layout. *@
@* Must declare its own rendermode so it gets its own interactive boundary. *@
@rendermode InteractiveServer
@using sv_eff8274fd0c04794ad69865263f57081.Services
@implements IDisposable
@inject NotificationHub Hub

<a href="notifications" class="notification-bell" title="Notifications">
    <span class="bi bi-bell-nav-menu" aria-hidden="true"></span>
    🔔
    @if (_unreadCount > 0)
    {
        <span class="badge bg-danger rounded-pill">@_unreadCount</span>
    }
</a>

@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += OnHubChanged;
    }

    /// <summary>
    /// Called by NotificationHub on ANY mutation — possibly from a
    /// background thread. InvokeAsync marshals to the render sync-context.
    /// </summary>
    private async Task OnHubChanged()
    {
        _unreadCount = Hub.GetUnreadCount();
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

.notification-bell {
    position: relative;
    display: inline-flex;
    align-items: center;
    color: white;
    text-decoration: none;
    font-size: 1.25rem;
    padding: 0.25rem 0.5rem;
}

.notification-bell:hover {
    color: #ffc107;
}

.notification-bell .badge {
    position: absolute;
    top: -4px;
    right: -4px;
    font-size: 0.65rem;
    padding: 0.2em 0.45em;
}

@* Interactive island showing up to 3 most recent unread notifications. *@
@rendermode InteractiveServer
@using sv_eff8274fd0c04794ad69865263f57081.Models
@using sv_eff8274fd0c04794ad69865263f57081.Services
@implements IDisposable
@inject NotificationHub Hub

<div class="card">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Recent Unread</strong>
        <span class="badge bg-secondary">@_recent.Count</span>
    </div>
    <ul class="list-group list-group-flush">
        @if (_recent.Count == 0)
        {
            <li class="list-group-item text-muted">No unread notifications.</li>
        }
        @foreach (var n in _recent)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <span class="badge bg-@SeverityColor(n.Severity) me-1">@n.Severity</span>
                    <strong>@n.Title</strong>
                    <br />
                    <small class="text-muted">@n.Message</small>
                </div>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => Dismiss(n.Id)">
                    Dismiss
                </button>
            </li>
        }
    </ul>
</div>

@code {
    private List<Notification> _recent = [];

    protected override void OnInitialized()
    {
        Refresh();
        Hub.OnChange += OnHubChanged;
    }

    private async Task OnHubChanged()
    {
        Refresh();
        await InvokeAsync(StateHasChanged);
    }

    private void Refresh()
    {
        _recent = Hub.Notifications
                      .Where(n => !n.IsRead)
                      .OrderByDescending(n => n.Timestamp)
                      .Take(3)
                      .ToList();
    }

    private async Task Dismiss(Guid id) => await Hub.DismissNotificationAsync(id);

    private static string SeverityColor(Severity s) => s switch
    {
        Severity.Critical => "danger",
        Severity.Warning  => "warning",
        _                 => "info"
    };

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using sv_eff8274fd0c04794ad69865263f57081.Models
@using sv_eff8274fd0c04794ad69865263f57081.Services
@implements IDisposable
@inject NotificationHub Hub

<PageTitle>Notifications</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h2>Notifications</h2>
    <button class="btn btn-primary" @onclick="MarkAllRead">Mark All Read</button>
</div>

@if (!Hub.Notifications.Any())
{
    <div class="alert alert-secondary">No notifications yet.</div>
}
else
{
    @foreach (var group in Hub.Notifications.GroupBy(n => n.Severity)
                              .OrderByDescending(g => g.Key))
    {
        <h4 class="mt-4">
            <span class="badge bg-@SeverityColor(group.Key)">@group.Key</span>
        </h4>
        <ul class="list-group mb-3">
            @foreach (var n in group.OrderByDescending(n => n.Timestamp))
            {
                <li class="list-group-item @(n.IsRead ? "" : "list-group-item-light fw-bold")
                           d-flex justify-content-between align-items-start">
                    <div>
                        <div>@n.Title</div>
                        <small class="text-muted">@n.Message</small>
                        <br />
                        <small class="text-muted">@n.Timestamp.ToString("g")</small>
                    </div>
                    <div class="btn-group btn-group-sm">
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-outline-success" @onclick="() => MarkRead(n.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-outline-danger" @onclick="() => Dismiss(n.Id)">
                            Dismiss
                        </button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
    protected override void OnInitialized()
    {
        Hub.OnChange += OnHubChanged;
    }

    private async Task OnHubChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    private async Task MarkRead(Guid id) => await Hub.MarkAsReadAsync(id);
    private async Task Dismiss(Guid id) => await Hub.DismissNotificationAsync(id);
    private async Task MarkAllRead()     => await Hub.MarkAllReadAsync();

    private static string SeverityColor(Severity s) => s switch
    {
        Severity.Critical => "danger",
        Severity.Warning  => "warning",
        _                 => "info"
    };

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

