@* Interactive island embedded in the static NavMenu layout. *@
@* Must declare its own rendermode so it gets its own interactive boundary. *@
@rendermode InteractiveServer
@using sv_eff8274fd0c04794ad69865263f57081.Services
@implements IDisposable
@inject NotificationHub Hub

<a href="notifications" class="notification-bell" title="Notifications">
    <span class="bi bi-bell-nav-menu" aria-hidden="true"></span>
    🔔
    @if (_unreadCount > 0)
    {
        <span class="badge bg-danger rounded-pill">@_unreadCount</span>
    }
</a>

@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += OnHubChanged;
    }

    /// <summary>
    /// Called by NotificationHub on ANY mutation — possibly from a
    /// background thread. InvokeAsync marshals to the render sync-context.
    /// </summary>
    private async Task OnHubChanged()
    {
        _unreadCount = Hub.GetUnreadCount();
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

